import React, { useEffect, useState, useRef, use, createElement } from "react";
import './myprofile.css'
import { useAuth } from "../../Context/useAuth";
import { Outlet, useLocation, useNavigate } from "react-router-dom";
import Sidebar from "../SideBar/Sidebar";
import { MoonLoader, BeatLoader, BarLoader} from "react-spinners";
import { saveProfileNoteImage, deleteProfileNoteImage, updateFontColor, updateProfileData } from "../../../API/Api";
import { motion, AnimatePresence } from "framer-motion";
import VerifiedBadge from "../Badge/VerifiedBadge";

import { useInfiniteQuery, useQuery, useQueryClient } from '@tanstack/react-query';
import Editor from "../HomePage/Editor/Editor";
import { useCallback } from "react";

import Cropper from "react-easy-crop";
import getCroppedImage from "../../utils/getCroppedImage";
import extractDominantColors from "../../utils/extractDominantColors";
import formatCounts from "../../../helpers/fomatCounts";
import MobileNavlink from "../mobileNavLink/MobileNavLink";
import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
import Loader from "../loadingComponent/BgLoader";

const DEFAULT_PROFILE_LAYOUT = {
    version: 1,
    preset: 'classic',
    spacing: 'md',
    radius: 'lg',
    sections: [
        {id: 'stats', visible: true, size: 'md', x: 24, y: 16},
        {id: 'bio', visible: true, size: 'md', x: 24, y: 108},
        {id: 'joined_date', visible: true, size: 'md', x: 24, y: 196},
    ]
};
const PROFILE_SECTION_LABELS = {
    stats: 'Stats',
    bio: 'Bio',
    joined_date: 'Joined date'
};
const PROFILE_SECTION_CODES = {
    stats: 'ST',
    bio: 'BIO',
    joined_date: 'JD'
};
const PROFILE_SECTION_IDS = Object.keys(PROFILE_SECTION_LABELS);
const PROFILE_SECTION_SIZES = ['sm', 'md', 'lg'];
const PROFILE_WIDGET_TYPES = ['note', 'photo_note'];
const PROFILE_WIDGET_SIZES = ['sm', 'md', 'lg'];
const PROFILE_WIDGET_GRID_SIZE = 24;
const PROFILE_SECTION_GRID_SIZE = 24;

const getDefaultSectionPosition = (sectionId) => {
    if(sectionId === 'stats'){
        return {x: 24, y: 16};
    }
    if(sectionId === 'bio'){
        return {x: 24, y: 108};
    }
    return {x: 24, y: 196};
};

const getDefaultWidgetPosition = (index = 0) => ({
    x: 24 + ((index % 2) * 240),
    y: 24 + (Math.floor(index / 2) * 144)
});

const createDefaultWidget = (index = 0) => {
    const defaultPosition = getDefaultWidgetPosition(index);
    return ({
    id: `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    type: 'note',
    size: 'md',
    title: 'New widget',
    note: '',
    image_url: '',
    x: defaultPosition.x,
    y: defaultPosition.y,
    height: null,
    image_width: null,
    image_height: null,
    pinned_section: null,
    blocks: []
});
};

const normalizeProfileLayout = (layout) => {
    const normalized = {
        version: layout?.version || DEFAULT_PROFILE_LAYOUT.version,
        preset: layout?.preset || DEFAULT_PROFILE_LAYOUT.preset,
        spacing: layout?.spacing || DEFAULT_PROFILE_LAYOUT.spacing,
        radius: layout?.radius || DEFAULT_PROFILE_LAYOUT.radius,
        sections: DEFAULT_PROFILE_LAYOUT.sections.map((section) => ({...section})),
        widgets: []
    };

    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    const normalizedSections = [];

    incomingSections.forEach((section) => {
        if(!PROFILE_SECTION_IDS.includes(section?.id)){
            return;
        }
        if(normalizedSections.find((item) => item.id === section.id)){
            return;
        }

        normalizedSections.push({
            id: section.id,
            visible: true,
            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : 'md',
            x: Number.isFinite(section?.x) ? Math.max(0, section.x) : getDefaultSectionPosition(section.id).x,
            y: Number.isFinite(section?.y) ? Math.max(0, section.y) : getDefaultSectionPosition(section.id).y,
            height: Number.isFinite(section?.height) ? Math.max(72, section.height) : null,
            content_width: Number.isFinite(section?.content_width) ? Math.max(120, section.content_width) : null,
            content_height: Number.isFinite(section?.content_height) ? Math.max(40, section.content_height) : null
        });
    });

    PROFILE_SECTION_IDS.forEach((sectionId) => {
        if(normalizedSections.find((section) => section.id === sectionId)){
            return;
        }

        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find((section) => section.id === sectionId);
        normalizedSections.push({...defaultSection});
    });

    normalized.sections = normalizedSections;

    const incomingWidgets = Array.isArray(layout?.widgets) ? layout.widgets : [];
    normalized.widgets = incomingWidgets
        .filter((widget) => widget && typeof widget === 'object')
        .map((widget) => ({
            id: widget.id || `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
            type: PROFILE_WIDGET_TYPES.includes(widget.type) ? widget.type : 'note',
            size: PROFILE_WIDGET_SIZES.includes(widget.size) ? widget.size : 'md',
            title: typeof widget.title === 'string' ? widget.title : '',
            note: typeof widget.note === 'string' ? widget.note : '',
            image_url: typeof widget.image_url === 'string' ? widget.image_url : '',
            x: Number.isFinite(widget?.x) ? Math.max(0, widget.x) : 24,
            y: Number.isFinite(widget?.y) ? Math.max(0, widget.y) : 24,
            height: Number.isFinite(widget?.height) ? Math.max(96, widget.height) : null,
            image_width: Number.isFinite(widget?.image_width) ? Math.max(60, widget.image_width) : null,
            image_height: Number.isFinite(widget?.image_height) ? Math.max(40, widget.image_height) : null,
            pinned_section: PROFILE_SECTION_IDS.includes(widget?.pinned_section) ? widget.pinned_section : null,
            blocks: Array.isArray(widget.blocks) ? widget.blocks
                .filter((b) => b && typeof b === 'object')
                .map((block) => ({
                    id: block.id || `block_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
                    type: ['text', 'image'].includes(block.type) ? block.type : 'text',
                    content: typeof block.content === 'string' ? block.content : '',
                    title: typeof block.title === 'string' ? block.title : '',
                    note: typeof block.note === 'string' ? block.note : '',
                    image_url: typeof block.image_url === 'string' ? block.image_url : '',
                    bg_color: typeof block.bg_color === 'string' ? block.bg_color : null,
                    x: Number.isFinite(block.x) ? Math.max(0, block.x) : 0,
                    y: Number.isFinite(block.y) ? Math.max(0, block.y) : 0,
                    width: Number.isFinite(block.width) ? Math.max(40, block.width) : 160,
                    height: Number.isFinite(block.height) ? Math.max(24, block.height) : 40,
                    image_width: Number.isFinite(block.image_width) ? block.image_width : null,
                    image_height: Number.isFinite(block.image_height) ? block.image_height : null
                }))
                : []
        }));

    return normalized;
};

