                const deltaX = latestEvent.clientX - widgetResizeState.startX;
                const directionalDelta = widgetResizeState.side === 'left' ? -deltaX : deltaX;
                const step = Math.trunc(directionalDelta / 70);
                const nextIndex = Math.max(0, Math.min(PROFILE_WIDGET_SIZES.length - 1, widgetResizeState.startIndex + step));
                if(nextIndex !== widgetResizeState.lastIndex){
                    handleWidgetFieldChange(widgetResizeState.widgetId, 'size', PROFILE_WIDGET_SIZES[nextIndex]);
                    setWidgetResizeState((previousState) => (
                        previousState
                            ? {...previousState, lastIndex: nextIndex}
                            : previousState
                    ));
                }
                widgetResizeRafRef.current = null;
            });
        };

        const handleMouseUp = () => {
            if(widgetResizeRafRef.current){
                window.cancelAnimationFrame(widgetResizeRafRef.current);
                widgetResizeRafRef.current = null;
            }
            setWidgetResizeState(null);
            if(!showLayoutBuilder){
                triggerAutoSave();
            }
        };

        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);

        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [widgetResizeState, showLayoutBuilder]);

