            const canvasRect = canvas.getBoundingClientRect();
            const widgetNode = canvas.querySelector(`[data-widget-id="${widgetMoveState.widgetId}"]`);
            const widgetWidth = widgetNode?.offsetWidth || 260;
            const maxX = Math.max(0, canvasRect.width - widgetWidth - 4);

            const rawX = Math.min(maxX, Math.max(0, widgetMoveState.originX + (e.clientX - widgetMoveState.startX)));
            const rawY = Math.max(0, widgetMoveState.originY + (e.clientY - widgetMoveState.startY));
            const snappedX = Math.min(maxX, Math.round(rawX / PROFILE_WIDGET_GRID_SIZE) * PROFILE_WIDGET_GRID_SIZE);
            const snappedY = Math.max(0, Math.round(rawY / PROFILE_WIDGET_GRID_SIZE) * PROFILE_WIDGET_GRID_SIZE);

            setProfileLayoutDraft((previousLayout) => ({
                ...previousLayout,
                widgets: previousLayout.widgets.map((widget) => (
                    widget.id === widgetMoveState.widgetId
                        ? {...widget, x: snappedX, y: snappedY}
                        : widget
                ))
            }));

            const sectionCanvas = sectionCanvasRef.current;
