                                                />
                                            </div>
                                            <button type="button" onClick={() => { handleRemoveWidget(widget.id); setEditingWidgetId(null); triggerAutoSave(); }} className="profile-widget-remove-button">Remove widget</button>
                                        </div>
                                    )}
                                    {editingWidgetId !== widget.id && (
                                        <>
                                            {widget.title && (
                                                <p className="profile-widget-title">{widget.title}</p>
                                            )}
                                            {widget.type === 'photo_note' && widget.image_url && renderWidgetImage(widget)}
                                            {widget.note && (
                                                <p className="profile-widget-note">{widget.note}</p>
                                            )}
                                        </>
                                    )}
                                    <div className="profile-resize-shell profile-widget-view-resize">
                                        <button
                                            type="button"
                                            className="profile-side-resize-handle left"
                                            onMouseDown={(e) => handleStartWidgetResize(e, widget.id, 'left')}
                                            aria-label="Resize widget from left"
                                        />
                                        <button
                                            type="button"
                                            className="profile-side-resize-handle right"
                                            onMouseDown={(e) => handleStartWidgetResize(e, widget.id, 'right')}
                                            aria-label="Resize widget from right"
                                        />
                                    </div>
                                    <button
                                        type="button"
                                        className="profile-vertical-resize-handle profile-widget-view-resize"
                                        onMouseDown={(e) => handleStartWidgetHeightResize(e, widget.id)}
                                        aria-label="Resize widget height"
                                    />
                                </div>
                            ))}

                        </div>
                        <button type="button" onClick={(e) => { handleAddWidget(); if(!showLayoutBuilder) triggerAutoSave(); }} className="profile-widget-add-button">+ Add widget</button>

                        <div className="profile-actions-row">
                            <div onClick={(e) => handleClickEdit(e)} className="edit-profile-bttn">
                                <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill={fontColor || userData?.profile_font_color}><path d="M200-120q-33 0-56.5-23.5T120-200v-560q0-33 23.5-56.5T200-840h357l-80 80H200v560h560v-278l80-80v358q0 33-23.5 56.5T760-120H200Zm280-360ZM360-360v-170l367-367q12-12 27-18t30-6q16 0 30.5 6t26.5 18l56 57q11 12 17 26.5t6 29.5q0 15-5.5 29.5T897-728L530-360H360Zm481-424-56-56 56 56ZM440-440h56l232-232-28-28-29-28-231 231v57Zm260-260-29-28 29 28 28 28-28-28Z"/></svg>
                                Edit Profile
                            </div>
                            <div onClick={(e) => handleClickFontColorSelector(e)} className="font-picker-container">
                                <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill={fontColor || userData?.profile_font_color}><path d="M80 0v-160h800V0H80Zm140-280 210-560h100l210 560h-96l-50-144H368l-52 144h-96Zm176-224h168l-82-232h-4l-82 232Z"/></svg>
                            </div>
                        </div>
                        {showLayoutBuilder && (
                            <div className="profile-layout-builder-actions">
                                <div onClick={(e) => handleCloseLayoutBuilder(e)} className="cancel-button">Cancel</div>
                                <div onClick={() => handleSaveProfileLayout()} className="save-button">Save</div>
                            </div>
                        )}

                        {showLayoutBuilder && isSavingLayout && (
                            <BarLoader loading={isSavingLayout} width={'100%'} color="rgb(40, 115, 255)" speedMultiplier={0.7}/>
                        )}

                    </div>


                    <div className="my-profile-tablist">
                        {tablists.map((tab, index) => (
                            <div onClick={() => tab.action()} className={"tab-container"} key={index}>
                                {tab.label}

                                <div className={location.pathname === tab.path ? "tab-indicator" : ''}></div>
                            </div>
                        ))}
                    </div>

                    <Outlet/>
                </div>

                <div className="profile-sidebar-right-holder-container">
                    {/* Log out */}
                </div>

                {/* hide and show sidebar through boolean */}
                {showMobileSideBar && ( 
                    <MobileSidebarLink onclose={handleCloseSidebar}/>
                )}

                <MobileNavlink clickOpenSidebar={handleClickOpenSidebar}/>
                <WriteJournalButton onOpen={opendRichTextEditor}/>
            </div>
        </AnimatePresence>
        </>
    )
}
export default MyProfile;
